// Format call data for Avoma API
const inputData = $input.first().json;

// Avoma expects a specific format for meeting notes
const avomaPayload = {
  // Meeting/Call identification
  external_id: inputData.call_id,
  title: `Call with ${inputData.metadata?.caller_name || 'Customer'}`,

  // Timing
  start_time: inputData.metadata?.started_at,
  end_time: inputData.metadata?.ended_at,
  duration_minutes: Math.ceil((inputData.metadata?.duration_seconds || 0) / 60),

  // Participants
  participants: [
    {
      name: inputData.metadata?.caller_name || 'Customer',
      email: null,
      role: 'external',
      is_organizer: false
    },
    {
      name: inputData.metadata?.agent_name || 'Agent',
      email: inputData.metadata?.agent_email || null,
      role: 'internal',
      is_organizer: true
    }
  ],

  // AI-generated content
  summary: inputData.analysis?.summary || '',

  // Key points from analysis
  key_points: [
    {
      type: 'customer_intent',
      content: inputData.analysis?.customer_intent || 'Not identified'
    },
    {
      type: 'resolution',
      content: `Status: ${inputData.analysis?.resolution_status || 'Unknown'}`
    },
    {
      type: 'sentiment',
      content: `Customer sentiment: ${inputData.analysis?.sentiment?.label || 'neutral'} (${inputData.analysis?.sentiment?.confidence || 0}% confidence)`
    }
  ],

  // Topics as tags
  tags: inputData.analysis?.topics || [],

  // Action items
  action_items: (inputData.analysis?.action_items || []).map((item, idx) => ({
    id: `action_${idx + 1}`,
    description: item,
    assignee: inputData.metadata?.agent_name || null,
    due_date: null,
    status: 'pending'
  })),

  // Full transcript
  transcript: {
    segments: (inputData.transcript?.segments || []).map(seg => ({
      speaker: seg.speaker || 'Unknown',
      start_time: seg.start,
      end_time: seg.end,
      text: seg.text
    }))
  },

  // Metadata
  source: 'call_center_ai',
  source_type: 'phone_call',
  call_direction: inputData.metadata?.direction || 'inbound',

  // Custom fields for call center context
  custom_fields: {
    caller_number: inputData.metadata?.caller_number,
    hubspot_contact_id: inputData.integrations?.hubspot_contact_id,
    entities_mentioned: inputData.analysis?.entities || []
  }
};

return { json: avomaPayload };

