parameters.functionCode:
// Return success response
const avomaResponse = $('Create Avoma Meeting').first().json;
const inputData = $('Avoma Sync Trigger').first().json;

return {
  json: {
    status: 'success',
    call_id: inputData.call_id,
    avoma_meeting_id: avomaResponse.id,
    avoma_url: avomaResponse.url || null,
    synced_at: new Date().toISOString()
  }
};

// Handle Avoma API error
const error = $input.first().json;
const inputData = $('Avoma Sync Trigger').first().json;

return {
  json: {
    status: 'error',
    call_id: inputData.call_id,
    error_message: error.message || 'Avoma sync failed',
    error_code: error.statusCode || 500,
    retry_eligible: true,
    failed_at: new Date().toISOString()
  }
};
